sys_script_include.script:
var rm = new sn_ws.RESTMessageV2('Global Mock API Companies', 'Default GET');
var response = rm.execute();
var data = JSON.parse(response.getBody());

for (var i = 0; i < data.length; i++) {
    var comp = data[i];
    gs.info("Processing company: " + comp.name + " / ID: " + comp.u_external_id);

    var gr = new GlideRecord('core_company');
    gr.addQuery('u_external_id', comp.u_external_id);
    gr.query();

    if (gr.next()) {
        gs.info("Updating existing company: " + comp.name);
        gr.name = comp.name;
        gr.street = comp.street;
        gr.city = comp.city;
        gr.zip = comp.zip;
        gr.phone = comp.phone;
        gr.update();
    } else {
        gs.info("Inserting new company: " + comp.name);
        gr.initialize();
        gr.u_external_id = comp.u_external_id;
        gr.name = comp.name;
        gr.street = comp.street;
        gr.city = comp.city;
        gr.zip = comp.zip;
        gr.phone = comp.phone;
        gr.insert();
    }
}
